+    public static Object scanAddI_loop_reassociate(int[] a, int[] r) {
+        int sum = 0;
+        int i = 0;
+        for (; i < a.length - 3; i += 4) {
+            // We cut the latency by a factor of 4, but increase the number of additions.
+            int old_sum = sum;
+            int v0 = a[i + 0];
+            int v1 = a[i + 1];
+            int v2 = a[i + 2];
+            int v3 = a[i + 3];
+            int v01 = v0 + v1;
+            int v23 = v2 + v3;
+            int v0123 = v01 + v23;
+            sum += v0123;
+            r[i + 0] = old_sum + v0;
+            r[i + 1] = old_sum + v01;
+            r[i + 2] = old_sum + v01 + v2;
+            r[i + 3] = old_sum + v0123;
+        }
+        for (; i < a.length; i++) {
+            sum += a[i];
+            r[i] = sum;
+        }
+        return r;
+    }
