-    protected int displayResults(ResultSet rs) throws SQLException {
-        int rows = 0;
-        ResultSetMetaData rsmd = rs.getMetaData();
-        int cols = rsmd.getColumnCount();
-        if (rs != null) {
-            rs.beforeFirst();
-            while (rs.next()) {
-                rows++;
-
-                for (int i = 0; i < cols; i++) {
-                    System.out.print(rs.getString(i + 1) + " ");
-                }
-                System.out.println();
-            }
-        }
-
-        return rows;
-    }
