+    // The lowerCase example demonstrates a lane-wise control-flow diamond.
+    public static Object lowerCaseB_loop(byte[] a, byte[] r) {
+        for (int i = 0; i < a.length; i++) {
+            byte c = a[i];
+            if (c >= 'A' && c <= 'Z') {
+                c += ('a' - 'A'); // c += 32
+            }
+            r[i] = c;
+        }
+        return r;
+    }
